// MULTI_LINE="line1\nline2"

// For specific environment files:
var envFile = ".env." + (process.env.NODE_ENV || "development");
require("dotenv").config({ path: envFile });

// .env.development:
// NODE_ENV=development
// DEBUG=true
// LOG_LEVEL=debug

// .env.production:
// NODE_ENV=production
// DEBUG=false
// LOG_LEVEL=error

// .env.example (committed to git, .env is in .gitignore):
// PORT=3000
// DB_HOST=localhost
// DB_NAME=myapp
// # Fill in your credentials:
// DB_USER=
// DB_PASSWORD=

console.log("Environment:", process.env.NODE_ENV);
console.log("Port:", process.env.PORT);
console.log("Debug:", process.env.DEBUG);

// Read environment variables
console.log("PATH:", process.env.PATH);
console.log("HOME:", process.env.HOME || process.env.USERPROFILE);
console.log("OS:", process.env.OS);

// Set environment variables (affects current process and children)
process.env.MY_CUSTOM_VAR = "custom-value";
process.env.NODE_ENV = "production";

// Child processes inherit current env
var spawn = require("child_process").spawn;
var child = spawn("node", ["-e", "console.log(process.env.MY_CUSTOM_VAR)"]);
child.stdout.on("data", function(data) {
  console.log("Child received:", data.toString().trim());
});

// Delete environment variable
delete process.env.MY_CUSTOM_VAR;
console.log("After delete:", process.env.MY_CUSTOM_VAR); // undefined

// List all environment variables (sorted)
Object.keys(process.env).sort().forEach(function(key) {
  // Avoid logging sensitive values in production
  if (key.includes("SECRET") || key.includes("PASSWORD")) {
    console.log(key + "=***");
  } else {
    console.log(key + "=" + process.env[key]);
  }
});

// npm install envalid
var envalid = require("envalid");
var { str, num, bool, url, email, json } = envalid;

var env = envalid.cleanEnv(process.env, {
  NODE_ENV: str({ choices: ["development", "production", "test"] }),
  PORT: num({ default: 3000, devDefault: 3000 }),
  API_KEY: str({ desc: "API key for external service" }),
  DEBUG: bool({ default: false }),
  DB_URL: url({ desc: "Database connection URL" }),
  ADMIN_EMAIL: email({ default: "admin@example.com" }),
  REDIS_CONFIG: json({ desc: "Redis config as JSON string" })
}, {
  strict: true,  // Throw on unknown env vars
  dotEnvPath: ".env",  // Auto-load .env file
});

// env is a frozen object with typed values
console.log("Port:", env.PORT);  // number
console.log("Debug:", env.DEBUG);  // boolean
console.log("Node env:", env.NODE_ENV);  // string, validated

// envalid provides:
// - Type coercion (string → number/bool/url)
// - Validation (choices, format)
// - Defaults
// - Clear error messages on failure
// - .env auto-loading
// - Strict mode catches typos

// Run: DEBUG=app:*,app:db* node app.js
// Or use comma-separated: DEBUG=app:server,app:db node app.js

var debug = require("debug");

var logServer = debug("app:server");
var logDb = debug("app:db");
var logAuth = debug("app:auth");

function startServer() {
  logServer("Starting server on port %d", 3000);
  logServer("Server started in %s mode", process.env.NODE_ENV);
}

function connectDatabase() {
  logDb("Connecting to database at %s", process.env.DB_HOST);
  logDb("Connection pool size: %d", 10);
}

function authenticateUser(user) {
  logAuth("Authenticating user: %s", user);
}

startServer();
connectDatabase();
authenticateUser("alice");

// With DEBUG=app:server,app:db:
// Starting server on port 3000
// Server started in development mode
// Connecting to database at localhost
// Connection pool size: 10

// With DEBUG=app:*:
// All three namespaces are enabled

// With DEBUG=app:*,-app:auth:
// All app namespaces EXCEPT auth

// The DEBUG env var controls the "debug" package:
// - Namespaces with * wildcard
// - Comma-separated namespaces
// - Exclude with -namespace
// - Colon-separated hierarchy (app:server:startup)
